class LiChaoTree:
    def __init__(self, lo, hi):
        self.lo   = lo
        self.hi   = hi
        self.line = None   # dominant line at this node
        self.left = None
        self.right = None

    def _eval(self, line, x):
        return line[0] * x + line[1] if line else float('inf')

    def add(self, line, lo=None, hi=None):
        if lo is None: lo, hi = self.lo, self.hi
        mid = (lo + hi) // 2
        if self.line is None:
            self.line = line; return
        # Determine which line wins at midpoint and each endpoint
        left_better  = self._eval(line, lo)  < self._eval(self.line, lo)
        mid_better   = self._eval(line, mid) < self._eval(self.line, mid)
        if mid_better:
            self.line, line = line, self.line   # swap: keep winner at midpoint
        if lo == hi: return
        if left_better != mid_better:
