            self.left.add(___________)
        else:
            if self.right is None: self.right = LiChaoTree(mid+1, hi)
            self.right.add(___________)

    def query(self, x, lo=None, hi=None):
        if lo is None: lo, hi = self.lo, self.hi
        best = self._eval(self.line, x)
        if lo == hi: return best
        mid = (lo + hi) // 2
        if x <= mid:
            return min(best, self.left.query(x, lo, mid)  if self.left  else float('inf'))
        else:
            return min(best, self.right.query(x, mid+1, hi) if self.right else float('inf'))
